import { Plugin } from 'esbuild';
import { AcceptedPlugin } from 'postcss';

interface PostcssPluginConfig {
    plugin: AcceptedPlugin;
    prepend?: boolean;
}
interface TailwindPluginOptions {
    configPath: string | undefined;
    postcssPlugins: (AcceptedPlugin | PostcssPluginConfig)[];
    cssModulesEnabled: boolean;
    cssModulesFilter: RegExp;
    cssModulesExcludePaths: RegExp[];
}

declare const tailwindPlugin: (options?: Partial<TailwindPluginOptions>) => Plugin;

export { tailwindPlugin as default, tailwindPlugin };
